2.1 Overview of plots
library(tidyplots)

p1 &lt;- study |&gt; 
  tidyplot(x = treatment, y = score, color = treatment) |&gt; 
  add_title(title = "p1") |&gt; 
  add_violin(trim = FALSE) |&gt; 
  add_sem_errorbar() |&gt; 
  add_data_points_beeswarm()
p2 &lt;- energy_week |&gt; 
  tidyplot(x = date, y = power, color = energy_source) |&gt; 
  add_title(title = "p2") |&gt; 
  add_areastack_relative()
p3 &lt;- study |&gt; 
  tidyplot(x = treatment, y = score, color = treatment) |&gt; 
  add_title(title = "p3") |&gt; 
  add_mean_bar(alpha = 0.4) |&gt; 
  add_sem_errorbar() |&gt; 
  add_data_points_beeswarm()

p4 &lt;- study |&gt; 
  tidyplot(x = group, y = score, color = dose) |&gt; 
  add_title(title = "p4") |&gt; 
  add_violin() |&gt; 
  add_data_points_beeswarm() |&gt; 
  add_test_asterisks(hide_info = TRUE)

p5 &lt;- study |&gt; 
  tidyplot(x = group, y = score, color = dose) |&gt; 
  add_title(title = "p5") |&gt; 
  add_boxplot() |&gt; 
  add_data_points_beeswarm() |&gt; 
  add_test_pvalue(hide_info = TRUE)
p6 &lt;- energy_week |&gt; 
  tidyplot(x = date, y = power, color = energy_source) |&gt; 
  add_title(title = "p6") |&gt; 
  add_areastack_absolute()
patchwork::wrap_plots(p1, p2, p3, p4, p5, p6, ncol = 2) |&gt; 
  save_plot("images/p1_p6.png",
    view_plot = FALSE, width = 190, height = 200) # width and height should be tailored
library(tidyplots)

p7 &lt;- energy |&gt; 
  tidyplot(y = energy, color = energy_source) |&gt; 
  add_donut() |&gt; 
  add_title(title = "p7")
df &lt;- "https://tidyplots.org/data/correlation-matrix.csv" |&gt;
  readr::read_csv(show_col_types =FALSE)
p8 &lt;- df |&gt; 
  tidyplot(x = x, y = y, color = correlation) |&gt; 
  add_title(title = "p8") |&gt; 
  add_heatmap() |&gt; 
  sort_x_axis_levels(order_x) |&gt; 
  sort_y_axis_levels(order_y) |&gt; 
  remove_x_axis() |&gt; remove_y_axis() |&gt; remove_legend_title()

p9 &lt;- spendings |&gt; 
  tidyplot(x = category, y = amount, color = category) |&gt; 
  add_title(title = "p9") |&gt; 
  add_sum_bar(width = 0.05, alpha = 1) |&gt; 
  add_sum_dot() |&gt; 
  add_sum_value(accuracy = 1) |&gt; 
  remove_legend() |&gt; 
  adjust_x_axis(rotate_labels = 45)

p10 &lt;- study |&gt; 
  tidyplot(x = participant, y = score, color = group, dodge_width = 0) |&gt; 
  add_title(title = "p10") |&gt; 
  add_line(group = participant, color = "#bbbbbb") |&gt; 
  add_data_points(size = 2.5)

p11 &lt;- energy |&gt; 
  tidyplot(y = energy, color = energy_source) |&gt; 
  add_pie() |&gt; 
  add_title(title = "p11")

p12 &lt;- time_course |&gt; 
  tidyplot(x = day, y = score, color = treatment) |&gt; 
  add_title(title = "p12") |&gt; 
  add_mean_line() |&gt; 
  add_sem_ribbon()
patchwork::wrap_plots(p7, p8, p9, p10, p11, p12, ncol = 2) |&gt; 
  save_plot("images/p7_p12.png",
    view_plot = FALSE, width = 200, height = 200) # width and height should be tailored
library(tidyplots)

p13 &lt;- energy |&gt; 
  tidyplot(x = year, y = energy, color = energy_type) |&gt; 
  add_title(title = "p13") |&gt; 
  add_barstack_absolute()

p14 &lt;- climate |&gt; 
  tidyplot(x = max_temperature) |&gt; 
  add_title(title = "p14") |&gt; 
  add_histogram()

p15 &lt;- energy |&gt; 
  tidyplot(x = year, y = energy, color = energy_type) |&gt; 
  add_title(title = "p15") |&gt; 
  add_barstack_relative()

p16 &lt;- animals |&gt; 
  tidyplot(x = weight, y = size) |&gt; 
  add_title(title = "p16") |&gt; 
  add_data_points(white_border = TRUE) |&gt; 
  add_data_labels_repel(
    label = animal, 
    data = max_rows(weight, n = 3),
    color = "#000000",
    min.segment.length = 0)

df &lt;- tibble::tibble(
  x = 1,
  y = 1,
  text = c("&lt;span style='font-size:20pt;'&gt;More (custom) plot types&lt;/span&gt;
    &lt;br&gt;&lt;br&gt;&lt;i&gt;extented with ggplot2 (extentions) using &lt;b&gt;add()&lt;/b&gt;&lt;/i&gt;."))

p17 &lt;- df |&gt; 
  tidyplot(x = x, y = y) |&gt; 
  add_title(title = "p17") |&gt; 
  add(ggtext::geom_richtext(
    ggplot2::aes(x = x, y = y, label = text), 
    data = df, 
    color = "#000000", 
    fill = "#ffcccc")) |&gt; 
  add(ggplot2::theme_bw()) |&gt; 
  adjust_size(width = 100)
design &lt;- "AB
           CD
           EE"

(p13 + p14 + p15 + p16 + p17 + patchwork::plot_layout(design = design)) |&gt; 
  save_plot("images/p13_p17.png",
    view_plot = FALSE, width = 165, height = 200) # width and height should be tailored

2.2 Anatomy of plot

study |&gt; 
  tidyplot(x = group, y = score, color = dose) |&gt; 
  add_mean_bar(alpha = 0.4) |&gt; 
  add_sem_errorbar() |&gt; 
  add_data_points_beeswarm(white_border = TRUE, size = 1.5) |&gt; 
  add_title(title = "My study") |&gt; 
  add_caption(caption = "Petterson et al.")












Note



All plots in tidyplots have absolute dimensions. By default this is 50 mm in width and 50 mm in height.

3.2 The scheme of add functions (e.g. bar plot)






Tip



Most add funtions in tidyplots follow the same scheme
add_&lt;statistical-entity&gt;_&lt;graphical-representation&gt;

add_mean_dot(), add_mean_dash(), add_mean_bar(), add_median_bar(), add_sum_bar() etc.
add_sem_errorbar(), add_sd_errorbar() etc.




library(tidyplots)

# View top 10 rows of the columns used
study |&gt; 
  dplyr::select(treatment, score) |&gt; 
  dplyr::slice_head(n = 10)

# A tibble: 10 × 2
   treatment score
   &lt;chr&gt;     &lt;dbl&gt;
 1 A             2
 2 A             4
 3 A             5
 4 A             4
 5 A             6
 6 B             9
 7 B             8
 8 B            12
 9 B            15
10 B            16



# Plot
p1 &lt;- study |&gt; 
  tidyplot(x = treatment, y = score, color = treatment) |&gt; 
  add_sum_bar() |&gt; add_title(title = "p1: sum bar")

p2 &lt;- study |&gt; 
  tidyplot(x = treatment, y = score, color = treatment) |&gt; 
  add_median_bar() |&gt; add_title(title = "p2: median bar")

p3 &lt;- study |&gt; 
  tidyplot(x = treatment, y = score) |&gt; 
  add_mean_bar() |&gt; add_title(title = "p3: mean bar")

p4 &lt;- p3 |&gt; 
  adjust_title(title = paste("p4: mean bar", "points", sep = "\n")) |&gt; 
  add_data_points_beeswarm(white_border = TRUE, size = 2)

p5 &lt;- p4 |&gt; 
  adjust_title(title = paste("p5: mean bar", "points", "line", sep = "\n")) |&gt; 
  add_mean_line()

p6 &lt;- p5 |&gt; 
  adjust_title(title = paste(
    "p6: mean bar", "points", "line", "area", sep = "\n")) |&gt; 
  add_mean_area(alpha = 0.6)




The scheme of add functions.

3.3 Color alpha vs. saturation (e.g. bar plot)

library(tidyplots)

# View top 10 rows of the columns used
study |&gt; 
  dplyr::select(treatment, score) |&gt; 
  dplyr::slice_head(n = 10)

# A tibble: 10 × 2
   treatment score
   &lt;chr&gt;     &lt;dbl&gt;
 1 A             2
 2 A             4
 3 A             5
 4 A             4
 5 A             6
 6 B             9
 7 B             8
 8 B            12
 9 B            15
10 B            16



# Plot
p1 &lt;- study |&gt; 
  tidyplot(
    x = treatment, 
    y = score, 
    color = treatment) |&gt;
  add_annotation_text(
    text = c("see me?", "see me?"), 
    x = c(2, 3), 
    y = 100, 
    angle = 90, 
    color = "#bb5566", 
    fontface = "bold") |&gt; 
  add_title(title = "p1") |&gt; 
  adjust_y_axis(limit = c(0, 200)) |&gt; 
  adjust_x_axis(limit = c(1, 4))

p2 &lt;- p1 |&gt; 
  adjust_title(title = "p2") |&gt; 
  add_sum_bar()

p3 &lt;- p1 |&gt; 
  adjust_title(title = "p3: decreased intensity via `alpha`") |&gt; 
  add_sum_bar(alpha = 0.5)

p4 &lt;- p1 |&gt; 
  adjust_title(title = "p4: decreased intensity via `saturation`") |&gt;
  add_sum_bar(saturation = 0.5)




Color alpha vs. saturation.

3.5 Remove plot elements (e.g. bar plot)

library(tidyplots)

# View top 10 rows of the columns used
study |&gt; 
  dplyr::select(treatment, score) |&gt; 
  dplyr::slice_head(n = 10)

# A tibble: 10 × 2
   treatment score
   &lt;chr&gt;     &lt;dbl&gt;
 1 A             2
 2 A             4
 3 A             5
 4 A             4
 5 A             6
 6 B             9
 7 B             8
 8 B            12
 9 B            15
10 B            16



# Plot
p1 &lt;- study |&gt; 
  tidyplot(
    x = treatment, 
    y = score, 
    color = treatment) |&gt; 
  add_mean_bar(alpha = 0.4) |&gt; 
  add_sem_errorbar() |&gt; 
  add_data_points_beeswarm() |&gt; 
  add_title(title = "p1")

p2 &lt;- p1 |&gt; 
  adjust_title(title = "p2: remove legend") |&gt; 
  remove_legend()

p3 &lt;- p2 |&gt; 
  adjust_title(title = "p3: remove x axis title") |&gt; 
  remove_x_axis_title()

p4 &lt;- p3 |&gt; 
  adjust_title(title = "p4: remove x axis labels") |&gt; 
  remove_x_axis_labels()

p5 &lt;- p4 |&gt; 
  adjust_title(title = "p5: remove y axis title") |&gt; 
  remove_y_axis_title()

p6 &lt;- p5 |&gt; 
  adjust_title(title = "p6: remove y axis labels") |&gt; 
  remove_y_axis_labels()




Remove plot elements.

3.7 Point shape and size (e.g. dot plot)

library(tidyplots)

# View top 10 rows of the columns used
animals |&gt; 
  dplyr::select(weight, size, animal) |&gt; 
  dplyr::slice_head(n = 10)

# A tibble: 10 × 3
      weight  size animal           
       &lt;dbl&gt; &lt;dbl&gt; &lt;chr&gt;            
 1 0.00012     1.5 Honeybee         
 2 0.00045    10   Monarch Butterfly
 3 0.0002     10   Dragonfly        
 4 0.00002     2.5 Firefly          
 5 0.003      17   Praying Mantis   
 6 0.0000025   1   Mosquito         
 7 0.000005    4   Ant              
 8 0.00001     0.8 Ladybug          
 9 0.0002      7.5 Grasshopper      
10 0.0004      9   Butterfly        



# Plot
p0 &lt;- animals |&gt; 
  tidyplot(x = weight, y = size)

p1 &lt;- p0 |&gt; 
  add_title(title = "p1: filled circle (default)") |&gt; 
  add_data_points(color = "#ddaa33", shape = 19)

p2 &lt;- p0 |&gt; 
  add_title(title = "p2: empty circle") |&gt; 
  add_data_points(color = "#ddaa33", shape = 1)

p3 &lt;- p0 |&gt; 
  add_title(title = "p3: filled triangle") |&gt; 
  add_data_points(color = "#ddaa33", shape = 17)

p4 &lt;- p0 |&gt; 
  add_title(title = "p4: empty triangle") |&gt; 
  add_data_points(color = "#ddaa33", shape = 2)

p5 &lt;- p0 |&gt; 
  add_title(title = "p5: enlarged and filled triangle") |&gt; 
  add_data_points(
    color = "#ddaa33", fill = "#004488", shape = 24, size = 2)

p6 &lt;- p0 |&gt; 
  add_title(title = paste(
    "p6: enlarged and filled triangle", "wider border", sep = "\n")) |&gt; 
  add_data_points(
    color = "#ddaa33", fill = "#004488", shape = 24, size = 2, 
    stroke = 2)







Note



See Section 6.1 and Section 6.2 for details about shape.





Change point shape and size.

3.8 Reference lines/rectangle (e.g. dot plot)

library(tidyplots)

# View top 10 rows of the columns used
animals |&gt; 
  dplyr::select(weight, speed) |&gt; 
  dplyr::slice_head(n = 10)

# A tibble: 10 × 2
      weight   speed
       &lt;dbl&gt;   &lt;dbl&gt;
 1 0.00012   0.72   
 2 0.00045   0.432  
 3 0.0002    2.09   
 4 0.00002   0.0432 
 5 0.003     0.144  
 6 0.0000025 0.054  
 7 0.000005  0.00216
 8 0.00001   0.054  
 9 0.0002    0.576  
10 0.0004    0.432  



p1 &lt;- animals |&gt; 
  tidyplot(x = weight, y = speed) |&gt; 
  add_data_points(white_border = TRUE) |&gt;
  add_title(title = "p1") 

p2 &lt;- p1 |&gt; 
  adjust_title(title = "p2: reference line (dotdash)") |&gt; 
  add_reference_lines(
    x = 4000, y = c(100, 200), linetype = "dotdash")

p3 &lt;- p1 |&gt; 
  adjust_title(title = "p3: annotation line (dashed)") |&gt; 
  add_annotation_line(
    x = 2000, xend = 2000, y = 20, yend = 150, linetype = "dashed") |&gt; 
  add_annotation_text(text = "line", x = 2000, y = 160)

p4 &lt;- p1 |&gt; 
  adjust_title(title = "p4: annotation line with arrowhead") |&gt; 
  add_annotation_line(
    x = 2000, xend = 2000, y = 20, yend = 150,
    arrow = grid::arrow(length = grid::unit(2, "mm"))) |&gt; 
  add_annotation_text(text = "line with arrowhead", x = 2000, y = 160)

p5 &lt;- p1 |&gt; 
  adjust_title(title = "p5: annotation rectangle (dotted)") |&gt; 
  add_annotation_rectangle(
    xmin = 2000, xmax = 6200, ymin = 20, ymax = 150, 
    linetype = "dotted", color = "#000000", fill = NA)

p6 &lt;- p1 |&gt; 
  adjust_title(title = "p6: filled annotation rectangle (dotted)") |&gt; 
  add_annotation_rectangle(
    xmin = 2000, xmax = 6200, ymin = 20, ymax = 150, 
    linetype = "dotted", color = "#000000", fill = "#eecc66")




Add reference lines or rectangle.

3.10 Assign colors (e.g. violin plot)

library(tidyplots)

# View top 10 rows of the columns used
study |&gt; 
  dplyr::select(group, score, dose) |&gt; 
  dplyr::slice_head(n = 10)

# A tibble: 10 × 3
   group   score dose 
   &lt;chr&gt;   &lt;dbl&gt; &lt;chr&gt;
 1 placebo     2 high 
 2 placebo     4 high 
 3 placebo     5 high 
 4 placebo     4 high 
 5 placebo     6 high 
 6 placebo     9 low  
 7 placebo     8 low  
 8 placebo    12 low  
 9 placebo    15 low  
10 placebo    16 low  



p1 &lt;- study |&gt; 
  tidyplot(
    x = group, 
    y = score, 
    color = dose) |&gt; 
  add_violin(trim = FALSE) |&gt; 
  add_data_points_beeswarm() |&gt; 
  add_title(title = "p1")  

p2 &lt;- p1 |&gt; 
  adjust_title(title = "p2: assign colors") |&gt; 
  adjust_colors(
    new_colors = c(
      "high" = "#bb5566", 
      "low" = "#ddaa33"))

p3 &lt;- study |&gt; 
  tidyplot(
    x = treatment, 
    y = score, 
    color = treatment) |&gt; 
  add_violin(trim = FALSE) |&gt; 
  add_data_points_beeswarm() |&gt; 
  add_title(title = "p3")

p4 &lt;- p3 |&gt; 
  adjust_title(title = "p4: assign colors") |&gt; 
  adjust_colors(
    new_colors = c(
      "A" = "#000000", 
      "B" = "#004488",
      "C" = "#bb5566", 
      "D" = "#ddaa33"))




Assign colors.

3.12 Add sum values (e.g. bar plot)

library(tidyplots)

# View top 10 rows of the columns used
spendings |&gt; 
  dplyr::select(category, amount) |&gt; 
  dplyr::slice_head(n = 10)

# A tibble: 10 × 2
   category       amount
   &lt;chr&gt;           &lt;dbl&gt;
 1 Food              100
 2 Transportation     40
 3 Housing          1200
 4 Utilities          80
 5 Education          75
 6 Insurance         200
 7 Food               60
 8 Utilities          50
 9 Food               90
10 Transportation     40



# Plot
p1 &lt;- spendings |&gt; 
  tidyplot(
    x = category, 
    y = amount, 
    color = category) |&gt; 
  add_sum_bar(alpha = 0.2) |&gt; 
  add_sum_dash() |&gt; 
  add_title(title = "p1") |&gt; 
  adjust_x_axis(rotate_labels = TRUE) |&gt; 
  remove_legend()

p2 &lt;- p1 |&gt; 
  adjust_title(title = "p2: add sum values") |&gt; 
  add_sum_value(accuracy = 1)

p3 &lt;- p1 |&gt; 
  adjust_title(title = paste(
    "p3: add sum values in black",
    "one decimal place",
    sep = "\n")) |&gt; 
  add_sum_value(accuracy = 0.1, color = "black")

p4 &lt;- p1 |&gt; 
  adjust_title(title = paste(
    "p4: add sum values in black",
    "rotate 45",
    sep = "\n")) |&gt; 
  add_sum_value(
    accuracy = 1, 
    color = "black",
    angle = 45, 
    hjust = -0.1) |&gt; 
  adjust_padding(top = 0.2)




Add sum values.

3.13 Sort axis levels (e.g. bar plot)

library(tidyplots)

